617:             &Token::Number { value, .. } => Ok(CalcNode::Leaf(Leaf::Number(value))),
618:             &Token::Dimension {
619:                 value, ref unit, ..
620:             } => {
621:                 if allowed.includes(CalcUnits::LENGTH) {
622:                     if let Ok(l) = NoCalcLength::parse_dimension_with_context(context, value, unit)
