680:                     "pi" => Leaf::Number(std::f32::consts::PI),
681:                     "infinity" => Leaf::Number(f32::INFINITY),
682:                     "-infinity" => Leaf::Number(f32::NEG_INFINITY),
683:                     "nan" => Leaf::Number(f32::NAN),
684:                     _ => {
685:                         if crate::color::parsing::rcs_enabled() &&
