709:     /// This is in charge of parsing, for example, `2 + 3 * 100%`.
710:     pub fn parse<'i, 't>(
711:         context: &ParserContext,
712:         input: &mut Parser<'i, 't>,
713:         function: MathFunction,
714:         allowed: AllowParse,
